  "exercises": [
    {
      "words": ["Je", "porte", "un", "chapeau."],
      "translation": "Ich trage einen Hut.",
      "explanation": "Bei A1-Sätzen folgt die Wortstellung: Subjekt (Je), Verb (porte), Artikel (un) und Nomen (chapeau). Das Verb steht direkt nach dem Subjekt."
    },
    {
      "words": ["Tu", "as", "une", "robe."],
      "translation": "Du hast ein Kleid.",
      "explanation": "Das Subjekt (Tu) kommt vor dem Verb (as), gefolgt von Artikel (une) und Nomen (robe). Bei 'avoir' steht das Objekt nach dem Verb."
    },
    {
      "words": ["Il", "a", "des", "chaussettes."],
      "translation": "Er hat Socken.",
      "explanation": "Subjekt (Il) + Verb (a) + Artikel (des) + Nomen (chaussettes). Bei 'avoir' folgt das Objekt nach dem Verb."
    },
    {
      "words": ["Elle", "est", "en", "jupe."],
      "translation": "Sie ist in einem Rock.",
      "explanation": "Subjekt (Elle) + Verb (est) + Präposition (en) + Artikel (une) und Nomen (jupe). 'En' wird mit Kleidung verwendet, gefolgt von Artikel und Nomen."
    },
    {
      "words": ["Nous", "aimons", "les", "manteaux."],
      "translation": "Wir mögen Mantel.",
      "explanation": "Subjekt (Nous) + Verb (aimons) + Artikel (les) + Nomen (manteaux). Bei 'aimer' steht das Objekt nach dem Verb, auch wenn es Plural ist."
    }
  ]
}
